exercises.solution_code:
#include <iostream>
#include <string>

class Matrix2x2
{
private:
    int m00{}, m01{}, m10{}, m11{};
public:
    Matrix2x2() = default;
    Matrix2x2(int a, int b, int c, int d) : m00{a}, m01{b}, m10{c}, m11{d} {}

    bool operator==(const Matrix2x2& rhs) const
    {
        return m00 == rhs.m00 && m01 == rhs.m01 && m10 == rhs.m10 && m11 == rhs.m11;
    }

    friend Matrix2x2 operator+(const Matrix2x2& l, const Matrix2x2& r);
    friend Matrix2x2 operator-(const Matrix2x2& l, const Matrix2x2& r);
    friend std::ostream& operator<<(std::ostream& out, const Matrix2x2& m);
    friend std::istream& operator>>(std::istream& in, Matrix2x2& m);
};

Matrix2x2 operator+(const Matrix2x2& l, const Matrix2x2& r)
{
    return {l.m00 + r.m00, l.m01 + r.m01, l.m10 + r.m10, l.m11 + r.m11};
}

Matrix2x2 operator-(const Matrix2x2& l, const Matrix2x2& r)
{
    return {l.m00 - r.m00, l.m01 - r.m01, l.m10 - r.m10, l.m11 - r.m11};
}

std::ostream& operator<<(std::ostream& out, const Matrix2x2& m)
{
    out << '[' << m.m00 << ", " << m.m01 << "]\n";
    return out << '[' << m.m10 << ", " << m.m11 << "]\n";
}

std::istream& operator>>(std::istream& in, Matrix2x2& m)
{
    return in >> m.m00 >> m.m01 >> m.m10 >> m.m11;
}

int main()
{
    Matrix2x2 m1{}, m2{};
    std::cin >> m1 >> m2;
    std::string op{};
    std::cin >> op;

    if (op == "add")
        std::cout << (m1 + m2);
    else if (op == "subtract")
        std::cout << (m1 - m2);
    else
        std::cout << (m1 == m2 ? "Equal" : "Not equal") << '\n';

    return 0;
}

