#include <cassert>
#include <iostream>
#include <numeric>
#include <string>
#include <vector>

class Accumulator
{
private:
    std::vector<int> m_data{};

public:
    void operator()(int value) { m_data.push_back(value); }

    int operator[](int index) const
    {
        assert(index >= 0 && index < static_cast<int>(m_data.size()));
        return m_data[static_cast<std::size_t>(index)];
    }

    explicit operator int() const
    {
        return std::accumulate(m_data.begin(), m_data.end(), 0);
    }
};

int main()
{
    Accumulator acc{};
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        std::string cmd{};
        std::cin >> cmd;

        if (cmd == "push")
        {
            int val{};
            std::cin >> val;
            acc(val);
        }
        else if (cmd == "get")
        {
            int idx{};
            std::cin >> idx;
            std::cout << "acc[" << idx << "] = " << acc[idx] << '\n';
        }
        else // sum
        {
            std::cout << "Sum = " << static_cast<int>(acc) << '\n';
        }
    }

    return 0;
}

